// Get a random sample
var sample = _samples[Math.floor(Math.random() * _samples.length)];
// Get a random image (full root-relative path) from the sample
var image = sample.images[Math.floor(Math.random() * sample.images.length)];
var imageName = image.split('/').pop();
// Set the image source
var img = doc.getElementById('τυχαίο-δείγμα-εικόνα');
img.src = getRelativePath(image);
// Set the image alt text
img.alt = imageName;
// Set the image title
img.title = imageName;
var title = doc.getElementById('τυχαίο-δείγμα-τίτλος');
let species = sample.species;
if(Array.isArray(species)) {
    species = species[Math.floor(Math.random() * species.length)];
}
title.dataset.unprocessedTitle = species;
if (taxon_extinct(species)) title.dataset.extinct = '1';
// Set the image link, deep-linking to this specific specimen on the destination page
var link = doc.getElementById('τυχαίο-δείγμα-σύνδεσμος');
link.href = getBaseURL() + taxon_to_link(species) + '#sample-' + sample.id;
link.addEventListener('click', () => trackEvent('random_sample', { taxon_id: species }));

